chrome.runtime.onInstalled.addListener(e=>{e.reason==="install"&&chrome.runtime.openOptionsPage()});chrome.runtime.onMessage.addListener((e,t,r)=>{if(e.type==="OPEN_OPTIONS")return chrome.runtime.openOptionsPage(),r({success:!0}),!0;if(e.type==="GET_TAB_INFO")return chrome.tabs.query({active:!0,currentWindow:!0},n=>{r({tab:n[0]})}),!0});chrome.commands.onCommand.addListener(e=>{e==="toggle-panel"&&chrome.tabs.query({active:!0,currentWindow:!0},t=>{const r=t[0]?.id;r&&chrome.tabs.sendMessage(r,{type:"DSA_MENTOR_TOGGLE"}).catch(()=>{})})});chrome.alarms.create("keepAlive",{periodInMinutes:.4});chrome.alarms.onAlarm.addListener(e=>{e.name});
